SELECT s.first_name || ' ' || s.last_name AS full_name, s.email 
FROM sailors s 
WHERE s.sailor_id NOT IN (
    SELECT sailor_id 
    FROM race_results rr
);

SELECT sailors.first_name, sailors.last_name
FROM sailors
JOIN race_results ON sailors.sailor_id = race_results.sailor_id;

SELECT COUNT(*) AS no_race_organizers
FROM organizers
WHERE organizer_id NOT IN (SELECT organizer_id FROM races);

SELECT AVG(r.ranking_points) as avg_ranking_points
FROM race_results r
JOIN sailors s ON r.sailor_id = s.sailor_id;
